function sliderPhoto() {
    var swiper = new Swiper('.photo .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        speed: 500,
        breakpoints: {
            320: {
                slidesPerView: 1.2,
                spaceBetween: 12,
            },
            768: {
                slidesPerView: 2.35,
                spaceBetween: 12,
            },
            993: {
                slidesPerView: 2.35,
                spaceBetween: 24,
            },
            1601: {
                slidesPerView: 2,
                spaceBetween: 24,
            }
        }
    })
}

function sliderProjects() {
    var swiper = new Swiper('.projects .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 24,
        speed: 500,
        navigation: {
            nextEl: ".projects .swiper-button-next",
            prevEl: ".projects .swiper-button-prev",
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 12,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 12,
            },
            768: {
                slidesPerView: 2,
                spaceBetween: 12,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 24,
            }
        }
    })
}

$(document).ready(function () {
  sliderPhoto();
  sliderProjects();

    // Tabs
    $(".tab").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab").removeClass("tab--active")
        $(this).addClass("tab--active")

        $(this).parents(".tabs-inner").find(".tab__content").removeClass("tab__content--active")
        $(this).parents(".tabs-inner").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active")
    })

    // Tabs--modal
    $(".tab-modal").click(function () {
        let path = $(this).attr("data-tab-path")
        $(this).siblings(".tab-modal").removeClass("tab-modal--active")
        $(this).addClass("tab-modal--active")

        $(this).parents(".wrapper").find(".tab-modal__content").removeClass("tab-modal__content--active")
        $(this).parents(".wrapper").find(`.tab-modal__content[data-content-path="${path}"]`).addClass("tab-modal__content--active")
    })

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })

    function closeModal() {
        $('.modal--active video').each(function () {
            this.pause();
            this.currentTime = 0;
        });

        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }


})

 // Zoom
    if (window.innerWidth <= 992) {

        const zoomBlocks = document.querySelectorAll('.js-pinch-zoom');

        zoomBlocks.forEach((box) => {

            const img = box.querySelector('img');
            const svg = box.querySelector('svg');

            /*
            =====================================
            COMMON
            =====================================
            */
            function getDistance(touches) {
            const dx = touches[0].clientX - touches[1].clientX;
            const dy = touches[0].clientY - touches[1].clientY;
            return Math.sqrt(dx * dx + dy * dy);
            }

            /*
            =====================================
            IMG ZOOM
            =====================================
            */
            if (img) {

            let scale = 1;

            let startDist = 0;

            let pointX = 0;
            let pointY = 0;

            let startX = 0;
            let startY = 0;

            let isDragging = false;

            function update() {
                img.style.transform =
                `translate(${pointX}px, ${pointY}px) scale(${scale})`;
            }

            box.addEventListener('touchstart', (e) => {

                if (e.touches.length === 2) {
                startDist = getDistance(e.touches);
                }

                if (e.touches.length === 1 && scale > 1) {
                isDragging = true;

                startX = e.touches[0].clientX - pointX;
                startY = e.touches[0].clientY - pointY;
                }

            }, { passive: false });

            box.addEventListener('touchmove', (e) => {

                if (e.touches.length === 2) {

                e.preventDefault();

                const newDist = getDistance(e.touches);
                const delta = newDist / startDist;

                scale = Math.min(Math.max(scale * delta, 1), 4);

                update();

                startDist = newDist;
                }

                if (e.touches.length === 1 && isDragging && scale > 1) {

                e.preventDefault();

                pointX = e.touches[0].clientX - startX;
                pointY = e.touches[0].clientY - startY;

                update();
                }

            }, { passive: false });

            box.addEventListener('touchend', () => {

                isDragging = false;

                if (scale <= 1) {
                scale = 1;
                pointX = 0;
                pointY = 0;
                update();
                }

            });
            }

            /*
            =====================================
            SVG ZOOM (PINCH TO POINT)
            =====================================
            */
            if (svg) {

            const base = svg.viewBox.baseVal;

            const original = {
                x: base.x,
                y: base.y,
                width: base.width,
                height: base.height
            };

            let viewBox = { ...original };

            let startDist = 0;

            let startX = 0;
            let startY = 0;

            let isDragging = false;

            let scale = 1;

            const minScale = 1;
            const maxScale = 4;

            function update() {
                svg.setAttribute(
                'viewBox',
                `${viewBox.x} ${viewBox.y} ${viewBox.width} ${viewBox.height}`
                );
            }

            box.addEventListener('touchstart', (e) => {

                if (e.touches.length === 2) {
                startDist = getDistance(e.touches);
                }

                if (e.touches.length === 1 && scale > 1) {
                isDragging = true;

                startX = e.touches[0].clientX;
                startY = e.touches[0].clientY;
                }

            }, { passive: false });

            box.addEventListener('touchmove', (e) => {

                /*
                =========================
                ZOOM TO FINGER POINT
                =========================
                */
                if (e.touches.length === 2) {

                e.preventDefault();

                const newDist = getDistance(e.touches);
                const delta = newDist / startDist;

                let newScale = scale * delta;
                newScale = Math.min(Math.max(newScale, minScale), maxScale);

                const rect = box.getBoundingClientRect();

                const cx =
                    (e.touches[0].clientX + e.touches[1].clientX) / 2;

                const cy =
                    (e.touches[0].clientY + e.touches[1].clientY) / 2;

                const offsetX = cx - rect.left;
                const offsetY = cy - rect.top;

                const svgX =
                    viewBox.x +
                    (offsetX / rect.width) * viewBox.width;

                const svgY =
                    viewBox.y +
                    (offsetY / rect.height) * viewBox.height;

                const zoomFactor = 1 / newScale;

                const newW = original.width * zoomFactor;
                const newH = original.height * zoomFactor;

                viewBox.x =
                    svgX - (offsetX / rect.width) * newW;

                viewBox.y =
                    svgY - (offsetY / rect.height) * newH;

                viewBox.width = newW;
                viewBox.height = newH;

                scale = newScale;

                update();

                startDist = newDist;
                }

                /*
                =========================
                DRAG
                =========================
                */
                if (e.touches.length === 1 && isDragging && scale > 1) {

                e.preventDefault();

                const dx = e.touches[0].clientX - startX;
                const dy = e.touches[0].clientY - startY;

                const moveX =
                    dx * (viewBox.width / box.clientWidth);

                const moveY =
                    dy * (viewBox.height / box.clientHeight);

                viewBox.x -= moveX;
                viewBox.y -= moveY;

                update();

                startX = e.touches[0].clientX;
                startY = e.touches[0].clientY;
                }

            }, { passive: false });

            box.addEventListener('touchend', () => {
                isDragging = false;

                if (scale <= 1) {
                scale = 1;
                viewBox = { ...original };
                update();
                }
            });
            }

        });
    }
